#include <stdio.h>
#include <stdlib.h>
#define MAXN 200000

int minServers(int n, int m, int connections[][2]) {
    int **graph = (int **)malloc(n * sizeof(int *));
    for (int i = 0; i < n; i++) {
        graph[i] = (int *)malloc(n * sizeof(int));
        for (int j = 0; j < n; j++) graph[i][j] = 0;
    }
    for (int i = 0; i < m; i++) {
        int a = connections[i][0] - 1;
        int b = connections[i][1] - 1;
        graph[a][b] = graph[b][a] = 1;
    }
    int *queue = (int *)malloc(n * sizeof(int));
    int *dist = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) dist[i] = -1;
    dist[0] = 0;
    int front = 0, rear = 1;
    queue[0] = 0;
    while (front < rear) {
        int u = queue[front++];
        for (int v = 0; v < n; v++) {
            if (graph[u][v] && dist[v] == -1) {
                queue[rear++] = v;
                dist[v] = dist[u] + 1;
            }
        }
    }
    free(graph);
    free(queue);
    free(dist);
    return dist[n - 1] == -1 ? -1 : dist[n - 1] + 1;
}

int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    int connections[m][2];
    for (int i = 0; i < m; i++) scanf("%d %d", &connections[i][0], &connections[i][1]);
    printf("%d\n", minServers(n, m, connections));
    return 0;
}

