#include <iostream>
#include <queue>
#include <vector>
using namespace std;

int minServers(int n, vector<pair<int, int>> connections) {
    vector<vector<int>> graph(n);
    for (auto &conn : connections) {
        graph[conn.first - 1].push_back(conn.second - 1);
        graph[conn.second - 1].push_back(conn.first - 1);
    }
    vector<int> dist(n, -1);
    dist[0] = 0;
    queue<int> q;
    q.push(0);
    while (!q.empty()) {
        int u = q.front(); q.pop();
        for (int v : graph[u]) {
            if (dist[v] == -1) {
                q.push(v);
                dist[v] = dist[u] + 1;
            }
        }
    }
    return dist[n - 1] == -1 ? -1 : dist[n - 1] + 1;
}

int main() {
    int n, m;
    cin >> n >> m;
    vector<pair<int, int>> connections(m);
    for (int i = 0; i < m; i++) cin >> connections[i].first >> connections[i].second;
    cout << minServers(n, connections) << endl;
    return 0;
}

