import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;

public class Main {
    public static int minServers(int n, int[][] connections) {
        int[][] graph = new int[n][n];
        for (int[] conn : connections) {
            graph[conn[0] - 1][conn[1] - 1] = 1;
            graph[conn[1] - 1][conn[0] - 1] = 1;
        }
        int[] dist = new int[n];
        for (int i = 0; i < n; i++) dist[i] = -1;
        dist[0] = 0;
        Queue<Integer> q = new LinkedList<>();
        q.add(0);
        while (!q.isEmpty()) {
            int u = q.poll();
            for (int v = 0; v < n; v++) {
                if (graph[u][v] == 1 && dist[v] == -1) {
                    q.add(v);
                    dist[v] = dist[u] + 1;
                }
            }
        }
        return dist[n - 1] == -1 ? -1 : dist[n - 1] + 1;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int m = scanner.nextInt();
        int[][] connections = new int[m][2];
        for (int i = 0; i < m; i++) {
            connections[i][0] = scanner.nextInt();
            connections[i][1] = scanner.nextInt();
        }
        System.out.println(minServers(n, connections));
    }
}

